import type { GadgetConnection } from "./GadgetConnection.js";
import type { ActionFunctionMetadata, AnyActionFunction, GlobalActionFunction } from "./GadgetFunctions.js";
import type { GadgetRecord } from "./GadgetRecord.js";
import { actionResultRunner } from "./operationRunners.js";
import type { DefaultSelection, Select } from "./types.js";

export type BackgroundActionResultData<SchemaT, Action extends AnyActionFunction> = Action extends ActionFunctionMetadata<
  any,
  any,
  any,
  SchemaT,
  any,
  any
>
  ? Action["hasReturnType"] extends true
    ? any
    : GadgetRecord<
        Select<
          Exclude<SchemaT, null | undefined>,
          DefaultSelection<Action["selectionType"], Action["optionsType"], Action["defaultSelection"]>
        >
      >
  : any;

export type BackgroundActionResult<Data = any> = {
  id: string;
  outcome: string | null;
  result: Data | null;
};

/** Represents a handle to a background action which has been enqueued */
export class BackgroundActionHandle<Action extends ActionFunctionMetadata<any, any, any, any, any, any> | GlobalActionFunction<any>> {
  constructor(readonly connection: GadgetConnection, readonly action: Action, readonly id: string) {}

  /** Wait for this background action to complete and return the result. */
  async result<SchemaT>(options?: Action extends ActionFunctionMetadata<any, any, any, any, any, any> ? Action["optionsType"] : never) {
    return (await actionResultRunner<SchemaT, Action>(this.connection, this.id, this.action, options)).result;
  }
}
